19: /**
20:  * Shared cache manager used by all instances of a health check filter configuration as well as
21:  * all threads. This sets up a timer that will invalidate the cached response code and allow some
22:  * requests to go through to the backend. No attempt is made to allow only a single request to go
23:  * through to the backend, so during the invalidation window some number of requests will get
24:  * through.
25:  */
26: class HealthCheckCacheManager {
27: public:
28:   HealthCheckCacheManager(Event::Dispatcher& dispatcher, std::chrono::milliseconds timeout);
29: 
30:   std::pair<Http::Code, bool> getCachedResponse() {
31:     return {last_response_code_, last_response_degraded_};
32:   }
33:   void setCachedResponse(Http::Code code, bool degraded) {
34:     last_response_code_ = code;
35:     last_response_degraded_ = degraded;
36:     use_cached_response_ = true;
37:   }
38:   bool useCachedResponse() { return use_cached_response_; }
39: 
40: private:
41:   void onTimer();
42: 
43:   Event::TimerPtr clear_cache_timer_;
44:   const std::chrono::milliseconds timeout_;
45:   std::atomic<bool> use_cached_response_{};
46:   std::atomic<Http::Code> last_response_code_{};
47:   std::atomic<bool> last_response_degraded_{};
48: };
49: 
50: using HealthCheckCacheManagerSharedPtr = std::shared_ptr<HealthCheckCacheManager>;
51: 
52: using ClusterMinHealthyPercentages = std::map<std::string, double>;
53: using ClusterMinHealthyPercentagesConstSharedPtr =
54:     std::shared_ptr<const ClusterMinHealthyPercentages>;
55: 
56: using HeaderDataVectorSharedPtr = std::shared_ptr<std::vector<Http::HeaderUtility::HeaderDataPtr>>;
57: 
58: /**
59:  * Health check responder filter.
60:  */
61: class HealthCheckFilter : public Http::StreamFilter {
62: public:
63:   HealthCheckFilter(Server::Configuration::ServerFactoryContext& context, bool pass_through_mode,
64:                     HealthCheckCacheManagerSharedPtr cache_manager,
65:                     HeaderDataVectorSharedPtr header_match_data,
66:                     ClusterMinHealthyPercentagesConstSharedPtr cluster_min_healthy_percentages)
67:       : context_(context), pass_through_mode_(pass_through_mode), cache_manager_(cache_manager),
68:         header_match_data_(std::move(header_match_data)),
69:         cluster_min_healthy_percentages_(cluster_min_healthy_percentages) {}
70: 
71:   // Http::StreamFilterBase
72:   void onDestroy() override {}
73: 
74:   // Http::StreamDecoderFilter
75:   Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers,
76:                                           bool end_stream) override;
77:   Http::FilterDataStatus decodeData(Buffer::Instance& data, bool end_stream) override;
78:   Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap& trailers) override;
79:   void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) override {
80:     callbacks_ = &callbacks;
81:   }
82: 
83:   // Http::StreamEncoderFilter
84:   Http::Filter1xxHeadersStatus encode1xxHeaders(Http::ResponseHeaderMap&) override {
85:     return Http::Filter1xxHeadersStatus::Continue;
86:   }
87:   Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap& headers,
88:                                           bool end_stream) override;
89:   Http::FilterDataStatus encodeData(Buffer::Instance&, bool) override {
90:     return Http::FilterDataStatus::Continue;
91:   }
92:   Http::FilterTrailersStatus encodeTrailers(Http::ResponseTrailerMap&) override {
93:     return Http::FilterTrailersStatus::Continue;
94:   }
95:   Http::FilterMetadataStatus encodeMetadata(Http::MetadataMap&) override {
96:     return Http::FilterMetadataStatus::Continue;
97:   }
98:   void setEncoderFilterCallbacks(Http::StreamEncoderFilterCallbacks&) override {}
99: 
100: private:
101:   void onComplete();
102: 
103:   Server::Configuration::ServerFactoryContext& context_;
104:   Http::StreamDecoderFilterCallbacks* callbacks_{};
105:   bool handling_{};
106:   bool health_check_request_{};
107:   bool pass_through_mode_{};
108:   HealthCheckCacheManagerSharedPtr cache_manager_;
109:   const HeaderDataVectorSharedPtr header_match_data_;
110:   ClusterMinHealthyPercentagesConstSharedPtr cluster_min_healthy_percentages_;
111: };
112: 
