17: 
18: namespace Envoy {
19: namespace Extensions {
20: namespace HttpFilters {
21: namespace HealthCheck {
22: 
23: struct RcDetailsValues {
24:   // The health check filter returned healthy to a health check.
25:   const std::string HealthCheckOk = "health_check_ok";
26:   // The health check filter responded with a failed health check.
27:   const std::string HealthCheckFailed = "health_check_failed";
28:   // The health check filter returned a cached health value.
29:   const std::string HealthCheckCached = "health_check_cached";
30:   // The health check filter failed due to health checking a nonexistent cluster.
31:   const std::string HealthCheckNoCluster = "health_check_failed_no_cluster_found";
32:   // The health check filter failed due to checking min_degraded against an empty cluster.
33:   const std::string HealthCheckClusterEmpty = "health_check_failed_cluster_empty";
34:   // The health check filter succeeded given the cluster health was sufficient.
35:   const std::string HealthCheckClusterHealthy = "health_check_ok_cluster_healthy";
36:   // The health check filter failed given the cluster health was not sufficient.
37:   const std::string HealthCheckClusterUnhealthy = "health_check_failed_cluster_unhealthy";
38: };
39: using RcDetails = ConstSingleton<RcDetailsValues>;
40: 
41: HealthCheckCacheManager::HealthCheckCacheManager(Event::Dispatcher& dispatcher,
42:                                                  std::chrono::milliseconds timeout)
43:     : clear_cache_timer_(dispatcher.createTimer([this]() -> void { onTimer(); })),
44:       timeout_(timeout) {
45:   onTimer();
46: }
47: 
48: void HealthCheckCacheManager::onTimer() {
49:   use_cached_response_ = false;
50:   clear_cache_timer_->enableTimer(timeout_);
51: }
52: 
53: Http::FilterHeadersStatus HealthCheckFilter::decodeHeaders(Http::RequestHeaderMap& headers,
54:                                                            bool end_stream) {
55:   if (Http::HeaderUtility::matchHeaders(headers, *header_match_data_)) {
56:     health_check_request_ = true;
57:     callbacks_->streamInfo().healthCheck(true);
58: 
59:     // Set the 'sampled' status for the span to false. This overrides
60:     // any previous sampling decision associated with the trace instance,
61:     // resulting in this span (and any subsequent child spans) not being
62:     // reported to the backend tracing system.
63:     callbacks_->activeSpan().setSampled(false);
64: 
65:     // If we are not in pass through mode, we always handle. Otherwise, we handle if the server is
66:     // in the failed state or if we are using caching and we should use the cached response.
67:     if (!pass_through_mode_ || context_.healthCheckFailed() ||
68:         (cache_manager_ && cache_manager_->useCachedResponse())) {
69:       handling_ = true;
70:     }
71:   }
72: 
73:   if (end_stream && handling_) {
74:     onComplete();
75:   }
76: 
77:   return handling_ ? Http::FilterHeadersStatus::StopIteration : Http::FilterHeadersStatus::Continue;
78: }
79: 
80: Http::FilterDataStatus HealthCheckFilter::decodeData(Buffer::Instance&, bool end_stream) {
81:   if (end_stream && handling_) {
82:     onComplete();
83:   }
84: 
85:   return handling_ ? Http::FilterDataStatus::StopIterationNoBuffer
86:                    : Http::FilterDataStatus::Continue;
87: }
88: 
89: Http::FilterTrailersStatus HealthCheckFilter::decodeTrailers(Http::RequestTrailerMap&) {
90:   if (handling_) {
91:     onComplete();
92:   }
93: 
94:   return handling_ ? Http::FilterTrailersStatus::StopIteration
95:                    : Http::FilterTrailersStatus::Continue;
96: }
97: 
98: Http::FilterHeadersStatus HealthCheckFilter::encodeHeaders(Http::ResponseHeaderMap& headers, bool) {
99:   if (health_check_request_) {
100:     if (cache_manager_) {
101:       cache_manager_->setCachedResponse(
102:           static_cast<Http::Code>(Http::Utility::getResponseStatus(headers)),
103:           headers.EnvoyDegraded() != nullptr);
104:     }
105: 
106:     headers.setEnvoyUpstreamHealthCheckedCluster(context_.localInfo().clusterName());
107:   }
108: 
109:   if (context_.healthCheckFailed()) {
110:     headers.setReferenceEnvoyImmediateHealthCheckFail(
111:         Http::Headers::get().EnvoyImmediateHealthCheckFailValues.True);
112:   }
113: 
114:   return Http::FilterHeadersStatus::Continue;
115: }
116: 
117: void HealthCheckFilter::onComplete() {
118:   ASSERT(handling_);
119:   Http::Code final_status = Http::Code::OK;
120:   const std::string* details = &RcDetails::get().HealthCheckOk;
121:   bool degraded = false;
122:   if (context_.healthCheckFailed()) {
123:     callbacks_->streamInfo().setResponseFlag(StreamInfo::CoreResponseFlag::FailedLocalHealthCheck);
124:     final_status = Http::Code::ServiceUnavailable;
125:     details = &RcDetails::get().HealthCheckFailed;
126:   } else {
127:     if (cache_manager_) {
128:       const auto status_and_degraded = cache_manager_->getCachedResponse();
129:       final_status = status_and_degraded.first;
130:       details = &RcDetails::get().HealthCheckCached;
131:       degraded = status_and_degraded.second;
132:     } else if (cluster_min_healthy_percentages_ != nullptr &&
133:                !cluster_min_healthy_percentages_->empty()) {
134:       // Check the status of the specified upstream cluster(s) to determine the right response.
135:       auto& clusterManager = context_.clusterManager();
136:       for (const auto& item : *cluster_min_healthy_percentages_) {
137:         details = &RcDetails::get().HealthCheckClusterHealthy;
138:         const std::string& cluster_name = item.first;
139:         const uint64_t min_healthy_percentage = static_cast<uint64_t>(item.second);
140:         auto* cluster = clusterManager.getThreadLocalCluster(cluster_name);
141:         if (cluster == nullptr) {
142:           // If the cluster does not exist at all, consider the service unhealthy.
143:           final_status = Http::Code::ServiceUnavailable;
144:           details = &RcDetails::get().HealthCheckNoCluster;
145: 
146:           break;
147:         }
148:         const auto& endpoint_stats = cluster->info()->endpointStats();
149:         const uint64_t membership_total = endpoint_stats.membership_total_.value();
150:         if (membership_total == 0) {
151:           // If the cluster exists but is empty, consider the service unhealthy unless
152:           // the specified minimum percent healthy for the cluster happens to be zero.
153:           if (min_healthy_percentage == 0UL) {
154:             continue;
155:           } else {
156:             final_status = Http::Code::ServiceUnavailable;
157:             details = &RcDetails::get().HealthCheckClusterEmpty;
158:             break;
159:           }
160:         }
161:         // In the general case, consider the service unhealthy if fewer than the
162:         // specified percentage of the servers in the cluster are available (healthy + degraded).
163:         if ((100UL * (endpoint_stats.membership_healthy_.value() +
164:                       endpoint_stats.membership_degraded_.value())) <
165:             membership_total * min_healthy_percentage) {
166:           final_status = Http::Code::ServiceUnavailable;
167:           details = &RcDetails::get().HealthCheckClusterUnhealthy;
168:           break;
169:         }
170:       }
171:     }
172: 
173:     if (!Http::CodeUtility::is2xx(enumToInt(final_status))) {
174:       callbacks_->streamInfo().setResponseFlag(
175:           StreamInfo::CoreResponseFlag::FailedLocalHealthCheck);
176:     }
177:   }
178: 
179:   callbacks_->sendLocalReply(
180:       final_status, "",
181:       [degraded](auto& headers) {
182:         if (degraded) {
183:           headers.setEnvoyDegraded("");
184:         }
185:       },
186:       absl::nullopt, *details);
187: }
188: 
189: } // namespace HealthCheck
190: } // namespace HttpFilters
191: } // namespace Extensions
192: } // namespace Envoy
