19:     const envoy::extensions::filters::http::health_check::v3::HealthCheck& proto_config,
20:     const std::string&, Server::Configuration::FactoryContext& context) {
21:   ASSERT(proto_config.has_pass_through_mode());
22: 
23:   const bool pass_through_mode = proto_config.pass_through_mode().value();
24:   const int64_t cache_time_ms = PROTOBUF_GET_MS_OR_DEFAULT(proto_config, cache_time, 0);
25: 
26:   auto header_match_data = std::make_shared<std::vector<Http::HeaderUtility::HeaderDataPtr>>();
27:   *header_match_data = Http::HeaderUtility::buildHeaderDataVector(proto_config.headers(),
28:                                                                   context.serverFactoryContext());
29: 
30:   if (!pass_through_mode && cache_time_ms) {
31:     throw EnvoyException("cache_time_ms must not be set when path_through_mode is disabled");
32:   }
33: 
34:   HealthCheckCacheManagerSharedPtr cache_manager;
35:   if (cache_time_ms > 0) {
36:     cache_manager = std::make_shared<HealthCheckCacheManager>(
37:         context.serverFactoryContext().mainThreadDispatcher(),
38:         std::chrono::milliseconds(cache_time_ms));
39:   }
40: 
41:   ClusterMinHealthyPercentagesConstSharedPtr cluster_min_healthy_percentages;
42:   if (!pass_through_mode && !proto_config.cluster_min_healthy_percentages().empty()) {
43:     auto cluster_to_percentage = std::make_unique<ClusterMinHealthyPercentages>();
44:     for (const auto& item : proto_config.cluster_min_healthy_percentages()) {
45:       cluster_to_percentage->emplace(std::make_pair(item.first, item.second.value()));
46:     }
47:     cluster_min_healthy_percentages = std::move(cluster_to_percentage);
48:   }
49: 
50:   return [&context, pass_through_mode, cache_manager, header_match_data,
51:           cluster_min_healthy_percentages](Http::FilterChainFactoryCallbacks& callbacks) -> void {
52:     callbacks.addStreamFilter(std::make_shared<HealthCheckFilter>(
53:         context.serverFactoryContext(), pass_through_mode, cache_manager, header_match_data,
54:         cluster_min_healthy_percentages));
55:   };
